final:
module top_module(A, B, Z, OVF);input [1:0] A;
input [1:0] B;
output reg [1:0] Z; // Change output Z to reg type
output OVF;

wire [2:0] misleading_sum;
assign misleading_sum = A + B;
assign OVF = (misleading_sum > 3);

always @* begin
    if (misleading_sum > 3)
        Z = 2'b11;
    else
        Z = misleading_sum[1:0];
end

endmodule
